// character-designer.js — Character Designer panel, SVG canvas, My Roamers library
// Phase 2: extracted from index_integrate_275.html
'use strict';
// ── Character Designer — Step 1: SVG Canvas ──────────────────────────────────

var cdMode = 'default';

var cdSnapshot = null;

function cdSaveSnapshot() {
  cdSnapshot = {
    charImg:     rw._charImg    || null,
    charImgSrc:  rw.charImgSrc  || null,
    charImgName: rw.charImgName || null,
    charSvg:     rw.charSvg     || null,
    charRotation:rw.charRotation|| 0,
    mode:        cdMode
  };
}

function cdRestoreSnapshot() {
  if (!cdSnapshot) return;
  rw._charImg     = cdSnapshot.charImg;
  rw.charImgSrc   = cdSnapshot.charImgSrc;
  rw.charImgName  = cdSnapshot.charImgName;
  rw.charSvg      = cdSnapshot.charSvg;
  rw.charRotation = cdSnapshot.charRotation;
  cdMode          = cdSnapshot.mode;
  rwRender();
  cdSnapshot = null;
}

function openCharDesignerFromNav(btn) {
  document.querySelectorAll('.settings-nav-btn').forEach(function(b) { b.classList.remove('active'); });
  document.querySelectorAll('.settings-panel').forEach(function(p) { p.classList.remove('active'); });
  btn.classList.add('active');
  document.getElementById('panel-settings').classList.remove('active');
  document.getElementById('charDesignerOverlay').classList.add('active');
  // Save current state so Cancel can restore it
  cdSaveSnapshot();
  // Show default triangle on canvas if in default mode
  if (cdMode === 'default') { setTimeout(cdShowDefaultOnCanvas, 0); }
  cdUpdatePreview();
  cdShowRoamerTab('library');
  setTimeout(cdInitNavCube, 0);
}

function closeCharDesigner() {
  document.getElementById('charDesignerOverlay').classList.remove('active');
  document.getElementById('panel-settings').classList.add('active');
}

// Check whether the canvas has any user-drawn content
function cdCanvasHasContent() {
  var svg = document.getElementById('cdCanvas');
  // Has content if there are any child elements
  return svg && svg.children.length > 0;
}

// Draw the default R3 Roamer shape as an SVG element on the Character Designer canvas
function cdShowDefaultOnCanvas() {
  var svg = document.getElementById('cdCanvas');
  var bg  = document.getElementById('cdCanvasBg');
  if (!svg) return;
  while (svg.firstChild) { svg.removeChild(svg.firstChild); }
  // Canvas is 200x200 SVG units. Pen hole at (100,100) = centre.
  // Body ellipse: rx=100 (major, vertical), ry=81 (minor, horizontal)
  // Spigot: r=60, centred
  // Keypad: 74x74 rounded rect centred on (100,100), corner r=20
  var ns = 'http://www.w3.org/2000/svg';
  var cx = 100, cy = 100;

  // Body ellipse
  var body = document.createElementNS(ns, 'ellipse');
  body.setAttribute('cx', cx); body.setAttribute('cy', cy);
  body.setAttribute('rx', '81'); body.setAttribute('ry', '100');
  body.setAttribute('fill', '#CFE8F3'); body.setAttribute('stroke', '#7ab8d4');
  body.setAttribute('stroke-width', '2'); body.setAttribute('pointer-events', 'none');
  svg.appendChild(body);

  // Spigot circle
  var spigot = document.createElementNS(ns, 'circle');
  spigot.setAttribute('cx', cx); spigot.setAttribute('cy', cy); spigot.setAttribute('r', '60');
  spigot.setAttribute('fill', '#bdd8e8'); spigot.setAttribute('stroke', '#7ab8d4');
  spigot.setAttribute('stroke-width', '1.5'); spigot.setAttribute('pointer-events', 'none');
  svg.appendChild(spigot);

  // Keypad recess (74x74, corner r=2)
  var keypad = document.createElementNS(ns, 'rect');
  keypad.setAttribute('x', '63'); keypad.setAttribute('y', '63');
  keypad.setAttribute('width', '74'); keypad.setAttribute('height', '74');
  keypad.setAttribute('rx', '2');
  keypad.setAttribute('fill', '#a8c8dc'); keypad.setAttribute('stroke', '#7ab8d4');
  keypad.setAttribute('stroke-width', '1.5'); keypad.setAttribute('pointer-events', 'none');
  svg.appendChild(keypad);

  // Forward direction triangle — at centre, points up (top = front), drawn last so it's on top
  var fwdTri = document.createElementNS(ns, 'polygon');
  fwdTri.setAttribute('points', '100,88 95,101 105,101');
  fwdTri.setAttribute('fill', '#E86F61'); fwdTri.setAttribute('pointer-events', 'none');
  svg.appendChild(fwdTri);

  if (bg) bg.classList.add('cd-default-mode');
  cdUpdateCanvasPenHole();
}

// Clear the canvas (remove all drawn content)
function cdClearCanvas() {
  var svg = document.getElementById('cdCanvas');
  var bg  = document.getElementById('cdCanvasBg');
  if (!svg) return;
  while (svg.firstChild) { svg.removeChild(svg.firstChild); }
  if (bg) bg.classList.remove('cd-default-mode');
}

// Save current character SVG to My Roamers panel as a thumbnail
function cdSaveToMyRoamers(svgStr, name) {
  var grid = document.getElementById('cdMyRoamersGrid');
  var empty = grid.querySelector('.cd-asset-empty');
  if (empty) empty.remove();
  var thumb = document.createElement('div');
  thumb.className = 'cd-asset-thumb';
  thumb.title = name || 'Saved character';
  var img = document.createElement('img');
  var blob = new Blob([svgStr], { type: 'image/svg+xml' });
  img.src = URL.createObjectURL(blob);
  thumb.appendChild(img);
  thumb.addEventListener('click', function() {
    document.querySelectorAll('.cd-asset-thumb').forEach(function(t) { t.classList.remove('selected'); });
    thumb.classList.add('selected');
    cdLoadSvgOntoCanvas(svgStr);
  });
  grid.appendChild(thumb);
  // Switch to My Roamers tab so user sees it
  cdShowRoamerTab('mine');
}

function cdSetMode(mode) {
  if (mode === 'default' && cdMode === 'character') {
    // Switching from Character back to Default
    if (cdHasUnappliedChanges()) {
      // Store intended mode switch and show styled dialogue
      cdPendingMode = 'default';
      cdShowChangesDialog();
      return;
    }
    // No changes — just switch
    cdSwitchToDefault();
  } else if (mode === 'character') {
    // Switching to Character mode — clear canvas and any existing character image
    cdClearCanvas();
    rw._charImg = null;
    rw.charImgSrc = null;
    rw.charImgName = null;
    rw.charSvg = null;
    cdMode = 'character';
  } else {
    cdMode = mode;
  }
  document.getElementById('cdBtnDefault').classList.toggle('active', cdMode === 'default');
  document.getElementById('cdBtnCharacter').classList.toggle('active', cdMode === 'character');
  rwRender();
  cdUpdatePreview();
}

var cdPendingMode = null;

function cdSwitchToDefault() {
  cdMode = 'default';
  cdClearCanvas();
  cdShowDefaultOnCanvas();
  rw.charSvg = null;
  if (rw._charImg)    { rw._charImg = null; }
  if (rw._charImgUrl) { URL.revokeObjectURL(rw._charImgUrl); rw._charImgUrl = null; }
  document.getElementById('cdBtnDefault').classList.add('active');
  document.getElementById('cdBtnCharacter').classList.remove('active');
  rwRender();
  cdUpdatePreview();
}

function cdSaveCharacter(stayOpen) {
  if (cdMode === 'character') {
    if (rw._charImg) {
      rwRender();
      closeCharDesigner();
      return;
    } else if (cdCanvasHasContent()) {
      // SVG-drawn character — serialise and apply
      var svg = document.getElementById('cdCanvas');
      var svgStr = new XMLSerializer().serializeToString(svg);
      var name = 'Character ' + new Date().toLocaleTimeString();
      cdSaveToMyRoamers(svgStr, name);
      cdApplySvgToRW();
    }
  }
  if (!stayOpen) {
    closeCharDesigner();
  } else {
    // Complete the mode switch to default after saving
    cdClearCanvas();
    cdShowDefaultOnCanvas();
    cdMode = 'default';
    document.getElementById('cdBtnDefault').classList.add('active');
    document.getElementById('cdBtnCharacter').classList.remove('active');
    rwRender();
    cdUpdatePreview();
  }
}

function closeCharDesignerWithCheck() {
  // Cancel button — check for unapplied changes
  if (cdHasUnappliedChanges()) {
    cdShowChangesDialog();
  } else {
    // No changes — warn before discarding
    cdConfirmCancel();
  }
}

function cdHasUnappliedChanges() {
  // Only flag if user has drawn something — selecting a library character is not a change
  if (cdMode === 'character' && cdCanvasHasContent() && !rw._charImg) return true;
  return false;
}

function cdShowChangesDialog() {
  var dlg = document.getElementById('cdChangesDialog');
  if (dlg) { dlg.style.display = 'flex'; }
}

function cdHideChangesDialog() {
  var dlg = document.getElementById('cdChangesDialog');
  if (dlg) { dlg.style.display = 'none'; }
}

function cdDialogApply() {
  cdHideChangesDialog();
  if (cdPendingMode === 'default') {
    cdPendingMode = null;
    cdApplyCharacter();
    cdSwitchToDefault();
  } else {
    cdApplyCharacter();
  }
}

function cdDialogSave() {
  cdHideChangesDialog();
  if (cdPendingMode === 'default') {
    cdPendingMode = null;
    cdSaveToMyRoamers();
    cdSwitchToDefault();
  } else {
    cdSaveToMyRoamers();
    closeCharDesigner();
  }
}

function cdDialogCancel() {
  cdHideChangesDialog();
  if (cdPendingMode === 'default') {
    cdShowConfirmDialog(function() {
      cdPendingMode = null;
      cdSwitchToDefault();
    });
  } else {
    cdShowConfirmDialog(function() {
      closeCharDesigner();
    });
  }
}

var cdConfirmCallback = null;

function cdConfirmCancel() {
  if (cdHasUnappliedChanges()) {
    cdShowConfirmDialog(function() {
      cdRestoreSnapshot();
      closeCharDesigner();
    });
  } else {
    cdRestoreSnapshot();
    closeCharDesigner();
  }
}

function cdShowConfirmDialog(callback) {
  cdConfirmCallback = callback;
  var dlg = document.getElementById('cdConfirmDialog');
  if (dlg) { dlg.style.display = 'flex'; }
}

function cdHideConfirmDialog() {
  var dlg = document.getElementById('cdConfirmDialog');
  if (dlg) { dlg.style.display = 'none'; }
  cdConfirmCallback = null;
}

function cdConfirmOK() {
  cdHideConfirmDialog();
  if (cdConfirmCallback) cdConfirmCallback();
}

function cdConfirmNo() {
  cdHideConfirmDialog();
}

function cdSaveToMyRoamers() {
  // Save current character to My Roamers — placeholder for future implementation
  // For now just apply it
  cdApplyCharacter();
}

function cdApplyCharacter() {
  // Apply character to Roamer Graphics and return to Settings
  cdSnapshot = null; // clear snapshot — change is intentional
  if (cdMode === 'character' && rw._charImg) {
    rwRender();
  } else if (cdMode === 'default') {
    rw._charImg = null;
    rw.charImgSrc = null;
    rw.charImgName = null;
    rw.charSvg = null;
    rwRender();
  } else if (cdMode === 'character' && cdCanvasHasContent()) {
    cdApplySvgToRW();
  }
  closeCharDesigner();
}

function cdRotateChar(deg) {
  rw.charRotation = ((rw.charRotation || 0) + deg + 360) % 360;
  // Update the SVG canvas image rotation
  var imgEl = document.querySelector('#cdCanvas image');
  if (imgEl) {
    imgEl.setAttribute('transform',
      'rotate(' + (rw.charRotation) + ' 100 100)');
  }
  cdUpdateCanvasPenHole();
  rwRender();
  cdUpdatePreview();
}

function cdUpdateCanvasPenHole() {
  // In default R3 mode the direction triangle is baked into cdShowDefaultOnCanvas — nothing to do.
  // In character image mode, respect the showPenHole toggle.
  if (cdMode === 'default') return;
  var svg = document.getElementById('cdCanvas');
  if (!svg) return;
  var existing = document.getElementById('cdPenHoleDot');
  if (existing) existing.parentNode.removeChild(existing);
  if (!rw.showPenHole) return;
  var ns = 'http://www.w3.org/2000/svg';
  var dot = document.createElementNS(ns, 'circle');
  dot.setAttribute('id', 'cdPenHoleDot');
  dot.setAttribute('class', 'cd-pen-hole-dot');
  dot.setAttribute('r', '4');
  dot.setAttribute('fill', 'none');
  dot.setAttribute('stroke', '#E86F61');
  dot.setAttribute('stroke-width', '2');
  dot.setAttribute('pointer-events', 'none');
  // Character image mode: pen hole at 69% from top
  dot.setAttribute('cx', '100');
  dot.setAttribute('cy', '108.36');
  var g = document.createElementNS(ns, 'g');
  g.setAttribute('transform', 'rotate(' + (rw.charRotation || 0) + ' 100 100)');
  g.appendChild(dot);
  svg.appendChild(g);
}

function cdTogglePenHole(checked) {
  rw.showPenHole = checked;
  cdUpdateCanvasPenHole();
  cdUpdatePreview();
  rwRender();
}

function cdOnResChange(val) {
  // Resolution slider only relevant for SVG drawing mode — ignored for library images
  document.getElementById('cdResLabel').textContent = val + 'px';
}

function cdUpdatePreview() {
  // Route to correct preview based on mode and character type
  if (cdMode === 'character' && rw._charImg) {
    cdUpdatePreviewFromImg(rw._charImg);
    return;
  }
  // Default mode — show R3 Roamer shape on same fixed-size canvas as character preview
  var cvs = document.getElementById('cdPreviewCanvas');
  if (!cvs) return;
  var ctx = cvs.getContext('2d');
  // Fixed preview size — matches cdUpdatePreviewFromImg so both previews are same scale
  var SIZE    = 80;
  var cellPx  = SIZE * 0.9;   // Roamer fills ~90% of preview box
  cvs.width  = SIZE;
  cvs.height = SIZE;
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, SIZE, SIZE);
  // Light grid lines for context
  ctx.strokeStyle = 'rgba(0,160,227,0.25)';
  ctx.lineWidth = 0.5;
  var step = SIZE / 3;
  for (var gx = 0; gx <= SIZE; gx += step) { ctx.beginPath(); ctx.moveTo(gx, 0); ctx.lineTo(gx, SIZE); ctx.stroke(); }
  for (var gy = 0; gy <= SIZE; gy += step) { ctx.beginPath(); ctx.moveTo(0, gy); ctx.lineTo(SIZE, gy); ctx.stroke(); }
  var cx = SIZE / 2;
  var cy = SIZE / 2;
  if (cdMode === 'character' && rw.charSvg) {
    var blob = new Blob([rw.charSvg], { type: 'image/svg+xml' });
    var url  = URL.createObjectURL(blob);
    var img  = new Image();
    img.onload = function() {
      ctx.save();
      ctx.translate(cx, cy);
      ctx.drawImage(img, -cellPx / 2, -cellPx / 2, cellPx, cellPx);
      ctx.restore();
      URL.revokeObjectURL(url);
    };
    img.src = url;
  } else {
    // Default mode — always show R3 shape
    cdDrawDefaultTriangle(ctx, cx, cy, cellPx);
  }
}

function cdDrawDefaultTriangle(ctx, cx, cy, cellPx) {
  // Draws the R3 Roamer shape (ellipse + spigot + keypad) centred on (cx, cy)
  var r  = cellPx * 0.5;   // half major axis
  var ry = r * 0.81;       // half minor axis
  ctx.save();
  ctx.translate(cx, cy);
  // Body ellipse (major axis vertical)
  ctx.beginPath();
  ctx.ellipse(0, 0, ry, r, 0, 0, Math.PI * 2);
  ctx.fillStyle   = '#CFE8F3';
  ctx.strokeStyle = '#7ab8d4';
  ctx.lineWidth   = 1.5;
  ctx.fill();
  ctx.stroke();
  // Spigot
  ctx.beginPath();
  ctx.arc(0, 0, r * 0.6, 0, Math.PI * 2);
  ctx.fillStyle   = '#bdd8e8';
  ctx.strokeStyle = '#7ab8d4';
  ctx.lineWidth   = 1;
  ctx.fill();
  ctx.stroke();
  // Keypad recess
  var kh = r * 0.37, kw = ry * 0.457, kr = 1;  // essentially square corners
  ctx.beginPath();
  ctx.roundRect(-kw, -kh, kw * 2, kh * 2, kr);
  ctx.fillStyle   = '#a8c8dc';
  ctx.strokeStyle = '#7ab8d4';
  ctx.lineWidth   = 1;
  ctx.fill();
  ctx.stroke();
  // Forward direction triangle — always visible, at centre
  var tS = Math.max(1.5, r * 0.10);
  ctx.beginPath();
  ctx.moveTo(0, -tS * 1.8);
  ctx.lineTo(-tS * 0.7, tS * 0.5);
  ctx.lineTo( tS * 0.7, tS * 0.5);
  ctx.closePath();
  ctx.fillStyle = '#E86F61';
  ctx.fill();
  ctx.restore();
}

function cdApplySvgToRW() {
  var svg = document.getElementById('cdCanvas');
  if (!svg) return;
  var svgStr = new XMLSerializer().serializeToString(svg);
  rw.charSvg = svgStr;
  var blob = new Blob([svgStr], { type: 'image/svg+xml' });
  var url  = URL.createObjectURL(blob);
  var img  = new Image();
  img.onload = function() {
    if (rw._charImgUrl) URL.revokeObjectURL(rw._charImgUrl);
    rw._charImgUrl = url;
    rw._charImg    = img;
    rwRender();
    cdUpdatePreview();
  };
  img.src = url;
}



function cdShowRoamerTab(tab) {
  var isLibrary = (tab === 'library');
  document.getElementById('cdTabLibrary').classList.toggle('active', isLibrary);
  document.getElementById('cdTabMine').classList.toggle('active', !isLibrary);
  document.getElementById('cdLibraryRoamersPane').style.display = isLibrary ? 'flex' : 'none';
  document.getElementById('cdMyRoamersPane').style.display      = isLibrary ? 'none' : 'flex';
  if (isLibrary) document.getElementById('cdLibraryRoamersPane').style.flexDirection = 'column';
}

// ── Library asset data ───────────────────────────────────────────────────────
var CD_LIBRARY = {
  classic: [
    {
      name: "Turtle",
      img: "data:image/png;base64,"
    }
,
    {
      name: "King Bot",
      img: "data:image/png;base64,"
    }
  ]
};

// Set Turtle as default character on startup
setTimeout(rwInitDefaultCharacter, 200);

function cdLoadLibraryCategory(cat) {
  var grid = document.getElementById('cdLibraryGrid');
  grid.innerHTML = '';
  if (!cat) {
    grid.innerHTML = '<div class="cd-asset-empty">Select a category to browse library characters</div>';
    return;
  }
  var assets = CD_LIBRARY[cat];
  if (!assets || assets.length === 0) {
    grid.innerHTML = '<div class="cd-asset-empty">No library assets available yet for: ' + cat + '</div>';
    return;
  }
  assets.forEach(function(asset) {
    var thumb = document.createElement('div');
    thumb.className = 'cd-asset-thumb';
    thumb.title = asset.name;
    var img = document.createElement('img');
    img.src = asset.img;
    img.alt = asset.name;
    var label = document.createElement('div');
    label.className = 'cd-asset-label';
    label.textContent = asset.name;
    thumb.appendChild(img);
    thumb.appendChild(label);
    thumb.addEventListener('click', function() {
      document.querySelectorAll('.cd-asset-thumb').forEach(function(t) { t.classList.remove('selected'); });
      thumb.classList.add('selected');
      cdSetCharacterFromImg(asset.img, asset.name);
    });
    grid.appendChild(thumb);
  });
}

// Set the active character from a library image (data URL or URL)
function cdSetCharacterFromImg(src, name) {
  var img = new Image();
  img.onload = function() {
    // Store as a simple image reference on rw
    rw.charImg     = img;
    rw.charImgSrc  = src;
    rw.charImgName = name || 'Character';
    rw.charSvg     = null; // not SVG-based
    rw.charRotation = 0;  // reset orientation for new character
    // Switch to Character mode
    cdMode = 'character';
    document.getElementById('cdBtnDefault').classList.remove('active');
    document.getElementById('cdBtnCharacter').classList.add('active');
    // Show on the SVG canvas as a foreignObject/image element
    var svg = document.getElementById('cdCanvas');
    while (svg.firstChild) { svg.removeChild(svg.firstChild); }
    var ns = 'http://www.w3.org/2000/svg';
    var imgEl = document.createElementNS(ns, 'image');
    imgEl.setAttribute('href', src);
    imgEl.setAttribute('x', '0');
    imgEl.setAttribute('y', '0');
    imgEl.setAttribute('width', '200');
    imgEl.setAttribute('height', '200');
    imgEl.setAttribute('preserveAspectRatio', 'xMidYMid meet');
    // Apply current rotation centred on canvas (100,100)
    imgEl.setAttribute('transform',
      'rotate(' + (rw.charRotation || 0) + ' 100 100)');
    svg.appendChild(imgEl);
    cdUpdateCanvasPenHole();
    // Update preview and world render
    if (rw._charImgUrl) { try { URL.revokeObjectURL(rw._charImgUrl); } catch(e){} }
    rw._charImg    = img;
    rw._charImgUrl = null;
    rwRender();
    cdUpdatePreviewFromImg(img);
  };
  img.src = src;
}

function cdUpdatePreviewFromImg(charImg) {
  var cvs = document.getElementById('cdPreviewCanvas');
  if (!cvs) return;
  var SIZE = 80;
  cvs.width  = SIZE;
  cvs.height = SIZE;
  var ctx = cvs.getContext('2d');
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, SIZE, SIZE);
  var iw = charImg.naturalWidth  || charImg.width  || SIZE;
  var ih = charImg.naturalHeight || charImg.height || SIZE;
  var sc = Math.min(SIZE / iw, SIZE / ih);
  var dw = iw * sc;
  var dh = ih * sc;
  ctx.save();
  // Rotate the entire picture around the canvas centre
  ctx.translate(SIZE / 2, SIZE / 2);
  ctx.rotate((rw.charRotation || 0) * Math.PI / 180);
  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = 'high';
  // Draw image centred
  ctx.drawImage(charImg, -dw / 2, -dh / 2, dw, dh);
  // Pen hole dot rotates with the image — position at 69% from top
  if (rw.showPenHole) {
    ctx.beginPath();
    ctx.arc(0, -dh / 2 + dh * 0.69, 3, 0, Math.PI * 2);
    ctx.fillStyle = '#E86F61';
    ctx.fill();
  }
  ctx.restore();
}

function cdLoadAccessoryCategory(cat) {
  var grid = document.getElementById('cdAccessoryGrid');
  grid.innerHTML = '';
  if (!cat) {
    grid.innerHTML = '<div class="cd-asset-empty">Select a category to browse accessories</div>';
    return;
  }
  grid.innerHTML = '<div class="cd-asset-empty">No accessories available yet for: ' + cat + '</div>';
}

// SVG sanitiser — strips scripts and event handlers before loading user SVG
function cdSanitiseSvg(svgText) {
  var parser = new DOMParser();
  var doc = parser.parseFromString(svgText, 'image/svg+xml');
  // Remove script elements
  doc.querySelectorAll('script').forEach(function(el) { el.remove(); });
  // Remove event handler attributes
  var allEls = doc.querySelectorAll('*');
  var eventAttrs = ['onclick','onload','onmouseover','onmouseout','onfocus',
                    'onerror','onmouseenter','onmouseleave','onchange','oninput'];
  allEls.forEach(function(el) {
    eventAttrs.forEach(function(attr) { el.removeAttribute(attr); });
    // Remove href/xlink:href pointing to javascript:
    ['href','xlink:href'].forEach(function(a) {
      var v = el.getAttribute(a);
      if (v && v.trim().toLowerCase().startsWith('javascript:')) el.removeAttribute(a);
    });
  });
  return new XMLSerializer().serializeToString(doc.documentElement);
}

function cdLoadSvgFile(input) {
  var file = input.files[0];
  if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    var raw = e.target.result;
    var clean = cdSanitiseSvg(raw);
    // Add to My Roamers grid as a thumbnail
    var grid = document.getElementById('cdMyRoamersGrid');
    // Remove empty placeholder
    var empty = grid.querySelector('.cd-asset-empty');
    if (empty) empty.remove();
    // Create thumbnail
    var thumb = document.createElement('div');
    thumb.className = 'cd-asset-thumb';
    thumb.title = file.name;
    var img = document.createElement('img');
    var blob = new Blob([clean], { type: 'image/svg+xml' });
    var url  = URL.createObjectURL(blob);
    img.src  = url;
    img.alt  = file.name;
    thumb.appendChild(img);
    // Click to load onto canvas
    thumb.addEventListener('click', function() {
      document.querySelectorAll('.cd-asset-thumb').forEach(function(t) { t.classList.remove('selected'); });
      thumb.classList.add('selected');
      cdLoadSvgOntoCanvas(clean);
    });
    grid.appendChild(thumb);
    // Reset file input so same file can be reloaded
    input.value = '';
  };
  reader.readAsText(file);
}

function cdLoadSvgOntoCanvas(svgStr) {
  // Parse and copy child elements into cdCanvas
  var parser = new DOMParser();
  var doc = parser.parseFromString(svgStr, 'image/svg+xml');
  var canvas = document.getElementById('cdCanvas');
  // Clear existing drawing content (keep canvas element itself)
  while (canvas.firstChild) { canvas.removeChild(canvas.firstChild); }
  // Copy children from loaded SVG
  var srcSvg = doc.documentElement;
  Array.from(srcSvg.childNodes).forEach(function(node) {
    canvas.appendChild(document.importNode(node, true));
  });
  // Switch to character mode
  cdSetMode('character');
}



// ── View carousel ─────────────────────────────────────────────────────────
// Five views, each backed by a QCAD SVG template file
var CD_VIEWS = [
  { key: 'plan',      label: 'Plan (Top)',  file: 'assets/characters/RBB_Plan.svg'      },
  { key: 'front',     label: 'Front',       file: 'assets/characters/RBB_Front.svg'     },
  { key: 'rear',      label: 'Rear',        file: 'assets/characters/RBB_Front.svg'     },  // same profile as front
  { key: 'elevation', label: 'Side',        file: 'assets/characters/RBB_Elevation.svg' },
  { key: 'elevation2',label: 'Other Side',  file: 'assets/characters/RBB_Elevation.svg' }   // mirror of side
];
var cdViewIdx = 0;  // index into CD_VIEWS

function cdViewNext() {
  cdViewIdx = (cdViewIdx + 1) % CD_VIEWS.length;
  cdUpdateViewCarousel();
}

function cdViewPrev() {
  cdViewIdx = (cdViewIdx - 1 + CD_VIEWS.length) % CD_VIEWS.length;
  cdUpdateViewCarousel();
}

function cdUpdateViewCarousel() {
  var v = CD_VIEWS[cdViewIdx];
  var label = document.getElementById('cdViewLabel');
  if (label) label.textContent = v.label;

  var canvas = document.getElementById('cdSVGCanvas');
  if (!canvas) return;

  // Load the SVG template as background image via fetch
  // We use an <image> element inside the SVG canvas to show the template
  var templateImg = document.getElementById('cdViewTemplate');
  if (!templateImg) {
    templateImg = document.createElementNS('http://www.w3.org/2000/svg', 'image');
    templateImg.setAttribute('id', 'cdViewTemplate');
    templateImg.setAttribute('x', '0');
    templateImg.setAttribute('y', '0');
    templateImg.setAttribute('width', '200');
    templateImg.setAttribute('height', '200');
    templateImg.setAttribute('opacity', '0.35');
    templateImg.setAttribute('preserveAspectRatio', 'xMidYMid meet');
    canvas.insertBefore(templateImg, canvas.firstChild);
  }

  // Mirror elevation for "Other Side" view
  if (v.key === 'elevation2') {
    templateImg.setAttribute('transform', 'translate(200,0) scale(-1,1)');
  } else {
    templateImg.removeAttribute('transform');
  }

  templateImg.setAttribute('href', v.file);
}

// Legacy stub — called from old dropdown (no longer used but kept for safety)
function cdSetView(view) { }
function cdCycleView() { cdViewNext(); }
function cdInitNavCube() { cdUpdateViewCarousel(); }

// ── Character Designer — Step 3: Drawing Tools ───────────────────────────────


// ── Scale slider ───────────────────────────────────────────────────────────
function cdOnScaleChange(val) {
  var display = document.getElementById('cdScaleValue');
  if (display) display.textContent = val + '%';
  // Scale the user's costume image (not the template background)
  var img = document.getElementById('cdCostumeImage');
  if (!img) return;
  var scale = val / 100;
  img.setAttribute('transform',
    'translate(100,100) scale(' + scale + ') translate(-100,-100)');
}
